import{_ as b,o as p,c as e,a2 as t}from"./chunks/framework.Nkqvsbxc.js";const l=JSON.parse('{"title":"禮佛大懺悔文","description":"","frontmatter":{},"headers":[],"relativePath":"scriptures/禮佛大懺悔文.md","filePath":"scriptures/禮佛大懺悔文.md"}'),a={name:"scriptures/禮佛大懺悔文.md"};function _(s,r,o,n,c,i){return p(),e("div",null,[...r[0]||(r[0]=[t('<h1 id="禮佛大懺悔文" tabindex="-1">禮佛大懺悔文 <a class="header-anchor" href="#禮佛大懺悔文" aria-label="Permalink to &quot;禮佛大懺悔文&quot;">​</a></h1><p>大慈大悲愍眾生，大喜大捨濟含識，<br> 相好光明以自嚴，眾等至心歸命禮。</p><p>南無歸依十方盡虛空界一切諸佛。<br> 南無歸依十方盡虛空界一切尊法。<br> 南無歸依十方盡虛空界一切賢聖僧。</p><p>南無如來、應供、正遍知、明行足、善逝世間解、無上士、調御丈夫、天人師、佛、世尊。</p><p>南無普光佛<br> 南無普明佛　<br> 南無普淨佛<br> 南無多摩羅跋栴檀香佛<br> 南無栴檀光佛<br> 南無摩尼幢佛<br> 南無歡喜藏摩尼寶積佛<br> 南無一切世間樂見上大精進佛<br> 南無摩尼幢燈光佛<br> 南無慧炬照佛<br> 南無海德光明佛<br> 南無金剛牢強普散金光佛<br> 南無大強精進勇猛佛<br> 南無大悲光佛<br> 南無慈力王佛<br> 南無慈藏佛<br> 南無栴檀窟莊嚴勝佛<br> 南無賢善首佛<br> 南無善意佛<br> 南無廣莊嚴王佛<br> 南無金華光佛<br> 南無寶蓋照空自在力王佛<br> 南無虛空寶華光佛<br> 南無琉璃莊嚴王佛<br> 南無普現色身光佛<br> 南無不動智光佛<br> 南無降伏眾魔王佛<br> 南無才光明佛<br> 南無智慧勝佛<br> 南無彌勒仙光佛<br> 南無善寂月音妙尊智王佛<br> 南無世淨光佛<br> 南無龍種上尊王佛<br> 南無日月光佛<br> 南無日月珠光佛<br> 南無慧幢勝王佛<br> 南無師子吼自在力王佛<br> 南無妙音勝佛<br> 南無常光幢佛<br> 南無觀世燈佛<br> 南無慧威燈王佛<br> 南無法勝王佛<br> 南無須彌光佛<br> 南無須曼那華光佛<br> 南無優曇鉢羅華殊勝王佛<br> 南無大慧力王佛<br> 南無阿閦毘歡喜光佛<br> 南無無量音聲王佛<br> 南無才光佛<br> 南無金海光佛<br> 南無山海慧自在通王佛<br> 南無大通光佛<br> 南無一切法常滿王佛</p><p>南無釋迦牟尼佛<br> 南無金剛不壞佛<br> 南無寶光佛<br> 南無龍尊王佛<br> 南無精進軍佛<br> 南無精進喜佛<br> 南無寶火佛<br> 南無寶月光佛<br> 南無現無愚佛<br> 南無寶月佛<br> 南無無垢佛<br> 南無離垢佛<br> 南無勇施佛<br> 南無清淨佛<br> 南無清淨施佛<br> 南無娑留那佛<br> 南無水天佛<br> 南無堅德佛<br> 南無栴檀功德佛<br> 南無無量掬光佛<br> 南無光德佛<br> 南無無憂德佛<br> 南無那羅延佛<br> 南無功德華佛<br> 南無蓮華光遊戲神通佛<br> 南無財功德佛<br> 南無德念佛<br> 南無善名稱功德佛<br> 南無紅燄帝幢王佛<br> 南無善遊步功德佛<br> 南無鬪戰勝佛<br> 南無善遊步佛<br> 南無周匝莊嚴功德佛<br> 南無寶華遊步佛<br> 南無寶蓮華善住娑羅樹王佛<br> 南無法界藏身阿彌陀佛</p><p>如是等一切世界諸佛世尊，常住在世。是諸世尊，當慈念我：若我此生、若我前生，從無始生死以來，所作眾罪，若自作、若教他作、見作隨喜；若塔若僧、若四方僧物，若自取、若教他取、見取隨喜；五無間罪，若自作、若教他作、見作隨喜；十不善道，若自作、若教他作、見作隨喜。所作罪障，或有覆藏、或不覆藏，應墮地獄、餓鬼、畜生，諸餘惡趣、邊地下賤，及蔑戾車如是等處。所作罪障，今皆懺悔。</p><p>今諸佛世尊，當證知我、當憶念我。我復於諸佛世尊前，作如是言：若我此生、若我前生，從無始生死以來，所作佈施、持戒、忍辱、精進、靜慮、智慧，所有善根；若我此生、若我前生，從無始生死以來，聽聞正法、讀誦受持、思惟修習，所有善根；若我此生、若我前生，從無始生死以來，孝養父母、禮敬師長、慈心不殺、修十善業，所有善根。以此善根，願共一切眾生，迴向阿耨多羅三藐三菩提。</p><p>眾罪皆懺悔，諸福盡隨喜，<br> 及請佛功德，願成無上智。<br> 去來現在佛，於眾生最勝，<br> 無量功德海，我今歸命禮。</p><p>所有十方世界中，三世一切人師子，<br> 我以清淨身語意，一切遍禮盡無餘。<br> 普賢行願威神力，普現一切如來前，<br> 一身復現剎塵身，一一遍禮剎塵佛。<br> 於一塵中塵數佛，各處菩薩眾會中，<br> 無盡法界塵亦然，深信諸佛皆充滿。<br> 各以一切音聲海，普出無盡妙言辭，<br> 盡於未來一切劫，讚佛甚深功德海。</p><p>以諸最勝妙華鬘，伎樂塗香及傘蓋，<br> 如是最勝莊嚴具，我以供養諸如來。<br> 最勝衣服最勝香，末香燒香與燈燭，<br> 一一皆如妙高聚，我悉供養諸如來。<br> 我以廣大勝解心，深信一切三世佛，<br> 悉以普賢行願力，普遍供養諸如來。</p><p>我昔所造諸惡業，皆由無始貪瞋癡，<br> 從身語意之所生，一切我今皆懺悔。<br> 十方一切諸眾生，二乘有學及無學，<br> 一切如來與菩薩，所有功德皆隨喜。</p><p>十方所有世間燈，最初成就菩提者，<br> 我今一切皆勸請，轉於無上妙法輪。<br> 諸佛若欲示涅槃，我悉至誠而勸請，<br> 唯願久住剎塵劫，利樂一切諸眾生。<br> 所有禮讚供養福，請佛住世轉法輪，<br> 隨喜懺悔諸善根，迴向眾生及佛道。</p><p>願將以此勝功德，迴向無上真法界，<br> 性相佛法及僧伽，二諦融通三昧印。<br> 如是無量功德海，我今皆悉盡迴向，<br> 所有眾生身口意，見惑彈謗我法等，<br> 如是一切諸業障，悉皆消滅盡無餘，<br> 念念智周於法界，廣度眾生皆不退。<br> 乃至虛空世界盡，眾生及業煩惱盡，<br> 如是四法廣無邊，願今迴向亦如是。</p><p>南無大行普賢願王菩薩摩訶薩（三稱）</p>',15)])])}const m=b(a,[["render",_]]);export{l as __pageData,m as default};
